"""RouterRunner — 조건부 분기 노드."""

from __future__ import annotations

import asyncio
import inspect
from typing import Any


class RouterRunner:
    async def run(self, node: Any, inputs: dict[str, Any], ctx: Any) -> dict[str, Any]:
        # Router는 입력을 그대로 반환. 라우팅 결정은 RouteResolver가 처리.
        instance = node.node_class() if node.node_class else None

        if instance is not None:
            # Generator 입력을 문자열로 소비
            resolved_inputs = {}
            for k, v in inputs.items():
                if hasattr(v, "__next__"):
                    resolved_inputs[k] = "".join(str(chunk) for chunk in v)
                else:
                    resolved_inputs[k] = v

            if inspect.iscoroutinefunction(getattr(instance, "execute", None)):
                result = await instance.execute(**resolved_inputs)
            elif hasattr(instance, "execute"):
                result = await asyncio.get_event_loop().run_in_executor(
                    None, lambda: instance.execute(**resolved_inputs),
                )
            else:
                result = resolved_inputs
        else:
            # node_class 없으면 입력을 그대로 반환
            result = inputs

        if isinstance(result, dict):
            return result
        return {"result": result}
